// Simulates a deadlock and resolves it.

const lockManager = require("./lock-manager");

function transactionA() {
  lockManager.acquire("T1", "row-1");
  const ok = lockManager.acquire("T1", "row-2");
  return ok;
}

function transactionB() {
  lockManager.acquire("T2", "row-2");
  const ok = lockManager.acquire("T2", "row-1");
  return ok;
}

transactionA();
transactionB();

const deadlock = lockManager.detectDeadlock();
console.log("Deadlock detected", deadlock);
if (deadlock) {
  console.log("Abort", deadlock[0]);
  lockManager.release(deadlock[0], "row-1");
  lockManager.release(deadlock[0], "row-2");
}

// Lock manager with deadlock detection.

const locks = new Map();
const waitsFor = new Map();

function acquire(tx, resource) {
  const owner = locks.get(resource);
  if (!owner) {
    locks.set(resource, tx);
    return true;
  }
  if (owner === tx) return true;

  waitsFor.set(tx, owner);
  return false;
}

function release(tx, resource) {
  if (locks.get(resource) === tx) {
    locks.delete(resource);
  }
  waitsFor.delete(tx);
}

function detectDeadlock() {
  for (const [tx, waitingOn] of waitsFor.entries()) {
    const next = waitsFor.get(waitingOn);
    if (next === tx) return [tx, waitingOn];
  }
  return null;
}

module.exports = { acquire, release, detectDeadlock };

