// Example client calls illustrating pagination and filtering.

const http = require("http");

function request(path) {
  return new Promise((resolve, reject) => {
    http.get(`http://localhost:4030${path}`, (res) => {
      let body = "";
      res.on("data", (chunk) => (body += chunk.toString("utf8")));
      res.on("end", () => resolve({ status: res.statusCode, body }));
    }).on("error", reject);
  });
}

async function run() {
  console.log("First page", await request("/orders?limit=2"));
  console.log("Second page", await request("/orders?limit=2&cursor=2"));
  console.log("Filtered", await request("/orders?status=shipped&minTotal=100&sort=total:desc"));
}

run().catch((error) => console.error(error));

// Standardized error envelope for API responses.

function errorPayload(code, message, details) {
  return { error: { code, message, details } };
}

module.exports = { errorPayload };

// Filter and sort helpers for orders.

function filterOrders(orders, query) {
  let result = orders.slice();

  if (query.status) {
    result = result.filter((order) => order.status === query.status);
  }

  if (query.minTotal !== undefined) {
    result = result.filter((order) => order.total >= query.minTotal);
  }

  if (query.maxTotal !== undefined) {
    result = result.filter((order) => order.total <= query.maxTotal);
  }

  if (query.sort) {
    const [field, direction] = query.sort.split(":");
    const dir = direction === "desc" ? -1 : 1;
    result = result.sort((a, b) => (a[field] > b[field] ? dir : -dir));
  }

  return result;
}

module.exports = { filterOrders };

