  console.log("GET /items/3", await request("GET", "/items/3"));

  console.log(
    "POST /sessions",
    await request("POST", "/sessions", { clientId: "client-42" })
  );
  console.log(
    "POST /sessions/hit",
    await request("POST", "/sessions/hit", { clientId: "client-42" })
  );
}

run().catch((error) => console.error(error));

